using Microsoft.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// Train the model at startup
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" label to boolean, featurize Region, and combine all features
var pipeline = mlContext.Transforms.CustomMapping<RawLabel, MappedLabel>(
        (input, output) => output.Label = string.Equals(input.Label, "Yes", StringComparison.OrdinalIgnoreCase),
        contractName: null)
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(dataView);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.WillChurn,
        Probability = prediction.Probability,
        Score = prediction.Score
    });
});

app.Run();

// Request DTO
public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

// Helper types for custom label mapping ("Yes"/"No" → bool)
public class RawLabel
{
    [Microsoft.ML.Data.ColumnName("Label")]
    public string Label { get; set; } = string.Empty;
}

public class MappedLabel
{
    [Microsoft.ML.Data.ColumnName("Label")]
    public bool Label { get; set; }
}

